<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div>
            <tg-list :IsShowAction="true" ModuleName="CRM" SubModuleCode="CRM_LEADS" :LegendArray="[]"
                :RenderRowActionMethod="renderActions" :widgets="[]" IdentityColumn="lead_consent_id"
                :HeaderText="$t('Consent')" :listType="['List']" :ListData="ListingData" :HeaderData="Headers"
                :TotalRecords="TotalRecords" :SearchFields="[]" IsSearchFieldsOnTop="false" SearchPosition="false"
                :ListDataCallBackFunction="FetchData" :showCheckBox="false" :SortExp="SortExp" :SortBy="SortBy"
                :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="[]"
                v-on:PagerButtonClick="pagerMethod" v-on:ActionButtonClick="actionButtonClick"
                v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">

                <template v-slot:slotdata="{ data }">

                    <template v-if="data.column.COLUMN_NAME == 'created_at'">
                        <span class="text-center single-action tourguide_a"
                            :title="$options.filters.formatDate(data.row.created_at)">
                            {{ $options.filters.formatDate(data.row.created_at) }}
                        </span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'Consent_datetime'">
                        <span class="text-center single-action tourguide_a"
                            :title="formatTimeFromDateTime(data.row.Consent_datetime)">
                            {{ formatTimeFromDateTime(data.row.Consent_datetime) }}
                        </span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME === 'file_path'">
                        <span title="">
                            <div class="input-group-append" style="font-size: 30px;">
                                <span v-if="data.row.file_path" id="basic-addon2" title="download"
                                    class="mx-1 input-group-text border-0 bg-info" style="width: 30px; height: 30px; border-radius: 100%; padding: 0px; text-align: center; 
                              display: flex; justify-content: center; cursor: pointer;">
                                    <a v-if="data.row.file_path"
                                        v-on:click="DownloadSingleFile(data.row.file_path, 'consent')" title="Download"
                                        style="font-size: 15px;" download>
                                        <i class="fa fa-download text-white action-icon enable"></i>
                                    </a>
                                </span>

                                <span v-else>
                                    <!-- <i class="fa fa-exclamation-triangle text-warning bg-seconday"
                                        title="No file available"></i> -->
                                </span>
                            </div>

                        </span>

                    </template>

                    <template v-if="data.column.COLUMN_NAME == 'status_id'">
                        <span class="px-2 text-center text-white d-block bg-success" :title="data.row.status_name"
                            v-if="data.row.status_name == 'Active'">
                            {{ $t("Active") }}
                        </span>
                        <span v-else-if="data.row.status_name == 'Inactive'" :title="data.row.status_name"
                            class="px-2 bg-danger text-center text-white d-block">
                            {{ $t("InActive") }}
                        </span>
                        <span v-else-if="data.row.status_name == 'Closed'" :title="data.row.status_name"
                            class="px-2 bg-warning text-center text-white d-block">
                            {{ $t("Closed") }}
                        </span>
                        <span v-else-if="data.row.status_name == 'Deleted'" :title="data.row.status_name"
                            class="px-2 bg-info text-center text-white d-block">
                            {{ $t("Deleted") }}
                        </span>
                        <span v-else class="px-2 bg-secondary text-center text-white d-block"
                            :title="data.row.status_name">
                            {{ data.row.status_name }}
                        </span>
                    </template>

                </template>

            </tg-list>

            <AddConsentDetails v-if="IsShowConsentDetailsForm" @FetchDataConsent="refreshFetchConsent" :LeadId="LeadId"
                :leadConsentId="leadConsentId" :EditConsentDetails='editConsentDetails'>
            </AddConsentDetails>
        </div>

    </section>
</template>
<script>
import DataService from "../../../services/DataService"
import AddConsentDetails from "./AddConsentDetails.vue";
import moment from 'moment';

export default {
    components: { AddConsentDetails },
    props: {

        sourceid: {
            type: String,
            required: true
        }
    },

    data() {
        return {

            TotalRecords: 0,
            noRecord: false,
            isLoading: false,
            PageSize: 10,
            PageNumber: 1,
            IsShowConsentDetailsForm: false,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            SortBy: '',
            SortExp: '',
            Headers: [

                {
                    "COLUMN_NAME": "Consent_datetime",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Consent datetime",
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true
                    }
                }, {
                    "COLUMN_NAME": "Consent_on",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Consent on",
                    "DISPLAY_ORDER": 2
                },
                {
                    "COLUMN_NAME": "Consent_by",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Consent by",
                    "DISPLAY_ORDER": 3
                },
                {
                    "COLUMN_NAME": "status_id",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Status",
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "created_at",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Created at",
                    "DISPLAY_ORDER": 5,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "created_by",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Created by",
                    "DISPLAY_ORDER": 6
                },
                {
                    "COLUMN_NAME": "file_path",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Attachment file",
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: true
                    }
                },

            ],
            ListingData: [],
            Buttons: [],
            SearchCondition: '',
            listActions:
                [
                    {
                        title: 'Edit',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-pencil text-info action-icon',
                        callbackfunction: 'Edit',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                ],
            leadConsentId: 0,
            LeadId: 0,
            editConsentDetails: {}
        };
    },
    created() {
        this.FetchData();
    },
    methods: {
        formatTimeFromDateTime(value) {
            if (value) {
                // Full date and time format
                return moment(value, "YYYY-MM-DD HH:mm:ss").format('MM/DD/YYYY h:mm A');
            }
            return '';
        },


        async FetchData() {
            var vm = this;
            vm.isLoading = true;
            var params = `Id=${vm.sourceid}&pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&searchCondition=${vm.SearchCondition}`;
            try {
                const response = await DataService.GetConsentDetails(params);
                if (response?.data) {
                    let data = JSON.parse(response.data.result).data;
                    if (data.length > 0) {
                        vm.isLoading = false;
                        vm.ListingData = data;
                        vm.noRecord = false;
                        vm.TotalRecords = data[0].TotalRecords;
                        vm.$emit('consentDetails', data)
                    } else {
                        vm.ListingData = [];
                        vm.noRecord = true;
                        vm.$emit('consentDetails', data)
                        // vm.TotalRecords = 0;
                        vm.isLoading = false;
                    }
                } else {
                    vm.noRecord = true;
                    vm.isLoading = false;
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            } catch (error) {
                vm.isLoading = false;
                vm.ListingData = [];
            }
        },

        leftCommonSearch(value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchCondition != '') {
                    let str = value.searchConditionJson;
                    let result = str.split('=')[1];
                    this.searchCondition = result;
                }
                else {
                    this.searchCondition = "";
                }
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Edit':
                        if (row.status_name == 'Closed') {
                            action.isVisible = true;
                            action.isDisabled = true
                        }
                        else {
                            action.isVisible = true;


                        }
                        break;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },

        pagerMethod(value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'Edit':
                    this.handleEdit(item);
                    break;
            }
        },

        handleEdit(item) {
            this.LeadId = item.lead_id
            this.leadConsentId = item.lead_consent_id;
            this.editConsentDetails = item;
            this.IsShowConsentDetailsForm = true;
        },
        async commonHeaderButtonClick(event) {
            var vm = this;
        },

        sortdata(s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },

        refreshFetchConsent() {
            var vm = this;
            vm.FetchData();
            vm.IsShowConsentDetailsForm = false;

        },
        getFileExtension(type) {
            const mimeType = type;
            const extension = mimeType.split('/')[1];
            return extension;
        },
        DownloadSingleFile(fileUrl, fileName) {
            var vm = this;
            vm.isLoading = true;
            if (fileUrl == null || fileUrl == "") {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("NoFileUrl"), "warning", true, vm.$t("Alert"));
            }
            else {
                var params = `FileUrl=${fileUrl}`
                DataService.DownloadSingleFile(params).then((response) => {
                    if (response.data != null) {
                        // const fileExtension = vm.getFileExtension(response.data.type);
                        const fileName = fileUrl.substring(fileUrl.lastIndexOf('/') + 1);
                        var fileURL = window.URL.createObjectURL(new Blob([response.data]));
                        var fileLink = document.createElement('a');
                        fileLink.href = fileURL;
                        fileLink.setAttribute('download', fileName);
                        document.body.appendChild(fileLink);
                        fileLink.click();
                        vm.isLoading = false;

                    }
                    else {
                        vm.isLoading = false;
                        vm.ShowAlert(vm.$t("FileNotDownload"), "warning", true, vm.$t("Alert"));
                    }

                })

            }

        },

    }
};
</script>