<template>
    <div>
        <template>
            <transition name="modal">
                <div class="modal d-block my-popups dialog">
                    <div class="modal-dialog">
                        <div class="modal-content">
                            <div class="modal-header">
                                <slot name="headerForModal">
                                    <h5 class="modal-title">{{ diagnosticDetailId == 0 ? $t("AddDiagonstic") :
                                        $t("EditDiagonstic") }}</h5>
                                </slot>
                                <button type="button" title v-on:click="closeAddDiagonstic" class="close"
                                    data-original-title="Close">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>
                            </div>
                            <div class="modal-body">


                                <loader :is-visible="isLoading"></loader>

                                <div class="dynamiccontent_base">
                                    <Form ref="AddDiagnostic">
                                        <dynamic-form ref="AddDiagnosticForm" v-on:OnSubmit="onSubmit" lang="en"
                                            :buttons="buttons" :schema="FormSchema">
                                        </dynamic-form>
                                    </Form>

                                </div>

                            </div>
                        </div>
                    </div>
                </div>
            </transition>
        </template>
    </div>
</template>

<script>

import DataService from "../../../services/DataService";

export default {
    props: {
        //
        LeadId: {
            type: String,
            required: true
        },
        diagnosticDetailId: {
            type: String,
            required: true
        }
    },

    components: {
    },
    data() {
        return {
            FormSchema: [],
            isLoading: false,
            buttons: [{
                type: "submit",
                class: "btn btn-success AddLeadDetail_a",
                text: "<i class='fa fa-save pr-2'></i>Save",
                onclick: this.saveForm
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Cancel",
                onClick: this.closeAddDiagonstic,
                isVisible: true,
            },
            ],

        };
    },

    async created() {
        var vm = this;
        vm.getForm();
    },
    methods: {
        closeAddDiagonstic() {
            this.$parent.IsShowAddDiagnosticForm = false
        },

        async getForm(id) {
            var vm = this;
            vm.isLoading = true;
            var url = `recordId=${this.diagnosticDetailId ? this.diagnosticDetailId : 0}&moduleName=CRM&subModuleCode=CRM_DIAGNOSTIC`;
            DataService.GetDynamicForm(url).then(function (response) {
                if (response != null && response.data != null) {
                    vm.FormSchema = vm.$refs.AddDiagnosticForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);
                    vm.FormSchema.forEach((group, gi) => {
                        group.Data.forEach((field, fi) => {
                            if (field.name == "lead_id") {
                                field.value = vm.LeadId;
                                console.log("Field", field);
                            }
                            if (field.name == "date_of_service") {
                                field.config.format = 'MM/DD/YYYY'
                            }
                        });
                    });
                    vm.isLoading = false;
                }
            });
        },

        onSubmit(val) {
            var vm = this;
            vm.$refs.AddDiagnosticForm.validateForm.validate().then(result => {
                if (result) {
                    vm.isLoading = true;
                    var CustomFieldArray = vm.$refs.AddDiagnosticForm.ConvertDynamicFormObjToCustomFieldObj(vm.FormSchema);
                    var obj = {
                        data: CustomFieldArray,
                        moduleCode: "CRM",
                        subModuleCode: "CRM_DIAGNOSTIC"
                    }
                    DataService.SaveDynamicForm(JSON.stringify(obj)).then(function (response) {
                        if (response != null && response.data != null && response.data[0].Status == "Success") {
                            vm.$emit("FetchDataDiagnostic");

                        } else {
                            vm.ShowAlert(vm.$t("ErrorWhileSaving", [vm.$t("Product")]), "danger", true, vm.$t("Alert"));
                            vm.isLoading = false;
                        }
                    })

                }
            });


        },


    },
};
</script>
