<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div>
            <tg-list :IsShowAction="true" ModuleName="CRM" SubModuleCode="CRM_LEADS" :LegendArray="[]"
                :RenderRowActionMethod="renderActions" :widgets="[]" IdentityColumn="diagnostic_detail_id"
                :listType="['List']" :ListData="ListingData" :HeaderData="Headers" :TotalRecords="TotalRecords"
                :SearchFields="[]" IsSearchFieldsOnTop="false" SearchPosition="false" :HeaderText="$t('DiagnosticDetails')"
                :ListDataCallBackFunction="FetchData" :showCheckBox="false" :SortExp="SortExp" :SortBy="SortBy"
                :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="[]"
                v-on:PagerButtonClick="pagerMethod" v-on:ActionButtonClick="actionButtonClick"
                v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">

                <template v-slot:slotdata="{ data }">

                    <template v-if="data.column.COLUMN_NAME == 'date_of_service'">
                        <span class="text-center single-action tourguide_a" :title="$options.filters.formatDate(data.row.date_of_service)">
                            {{ $options.filters.formatDate(data.row.date_of_service) }}
                        </span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'status_id'">
                        <span class="px-2 text-center text-white d-block bg-success" :title="data.row.status_name"
                            v-if="data.row.status_name == 'Active'">
                            {{ $t("Active") }}
                        </span>
                        <span v-else-if="data.row.status_name == 'Inactive'" :title="data.row.status_name"
                            class="px-2 bg-danger text-center text-white d-block">
                            {{ $t("InActive") }}
                        </span>
                        <span v-else-if="data.row.status_name == 'Closed'" :title="data.row.status_name"
                            class="px-2 bg-warning text-center text-white d-block">
                            {{ $t("Closed") }}
                        </span>
                        <span v-else-if="data.row.status_name == 'Prospect'" :title="data.row.status_name"
                            class="px-2 bg-info text-center text-white d-block">
                            {{ $t("Prospect") }}
                        </span>
                        <span v-else class="px-2 bg-secondary text-center text-white d-block"
                            :title="data.row.status_name">
                            {{ data.row.status_name }}
                        </span>
                    </template>

                </template>

            </tg-list>

            <AddDiagnosticForm v-if="IsShowAddDiagnosticForm" @FetchDataDiagnostic="refreshFetchDiagnosticData"
                :LeadId="LeadId" :diagnosticDetailId="diagnosticDetailId">
            </AddDiagnosticForm>
        </div>

    </section>
</template>
<script>
import DataService from "../../../services/DataService"
import AddDiagnosticForm from "./AddDiagnosticForm.vue";
export default {
    components: { AddDiagnosticForm },
    props: {
        // ClientId: {
        //     type: Number
        // }
        sourceid: {
            type: String,
            required: true
        }
    },
    data() {
        return {

            TotalRecords: 0,
            noRecord: false,
            isLoading: false,
            PageSize: 10,
            PageNumber: 1,
            IsShowAddDiagnosticForm: false,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            SortBy: '',
            SortExp: '',

            Headers: [
                //     {
                //     "COLUMN_NAME": "diagnostic_detail_id",
                //     "DATA_TYPE": "string",
                //     "SORTABLE": true,
                //     "VISIBLE": true,
                //     "DISPLAY_NAME": "diagnostic_detail_id",
                //     "DISPLAY_ORDER": 1
                //    },
                // {
                //     "COLUMN_NAME": "lead_id",
                //     "DATA_TYPE": "string",
                //     "SORTABLE": true,
                //     "VISIBLE": true,
                //     "DISPLAY_NAME": "Lead Name",
                //     "DISPLAY_ORDER": 2
                // },
                {
                    "COLUMN_NAME": "date_of_service",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "date of service",
                    "DISPLAY_ORDER": 3,
                    settings: {
                        isInSlot: true
                    }
                }, {
                    "COLUMN_NAME": "diagnosis_code1",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Code 1",
                    "DISPLAY_ORDER": 4
                },
                {
                    "COLUMN_NAME": "diagnosis_description1",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "description 1",
                    "DISPLAY_ORDER": 5
                },
                {
                    "COLUMN_NAME": "diagnosis_code2",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Code 2",
                    "DISPLAY_ORDER": 6
                },
                {
                    "COLUMN_NAME": "diagnosis_description2",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "description 2",
                    "DISPLAY_ORDER": 7
                },
                {
                    "COLUMN_NAME": "diagnosis_code3",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Code 3",
                    "DISPLAY_ORDER": 8
                },
                {
                    "COLUMN_NAME": "diagnosis_description3",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "description 3",
                    "DISPLAY_ORDER": 9
                }
                ,
                {
                    "COLUMN_NAME": "diagnosis_code4",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Code 4",
                    "DISPLAY_ORDER": 10
                },
                {
                    "COLUMN_NAME": "diagnosis_description4",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "description 4",
                    "DISPLAY_ORDER": 11
                },
                {
                    "COLUMN_NAME": "status_id",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Status",
                    "DISPLAY_ORDER": 12,
                    settings: {
                        isInSlot: true
                    }
                }
            ],
            ListingData: [],
            Buttons: [],
            SearchCondition: '',
            listActions:
                [
                    {
                        title: 'Edit',
                        href: 'javascript:void(0)',
                        icon: 'fa fa-pencil text-info action-icon',
                        callbackfunction: 'Edit',
                        isDisabled: false,
                        additionalSpan: ''
                    },
                ],
            diagnosticDetailId: 0,
            LeadId: 0
        };
    },
    created() {
        this.FetchData();
    },
    methods: {

        async FetchData() {
            var vm = this;
            vm.isLoading = true;
            var params = `Id=${vm.sourceid}&pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&searchCondition=${vm.SearchCondition}`;
            try {
                const response = await DataService.GetDiagnosticList(params);
                if (response?.data) {
                    let data = JSON.parse(response.data.result).data;
                    if (data.length > 0) {
                        vm.isLoading = false;
                        vm.ListingData = data;
                        vm.noRecord = false;
                        vm.TotalRecords = data[0].TotalRecords;
                    } else {
                        vm.ListingData = [];
                        vm.noRecord = true;
                        // vm.TotalRecords = 0;
                        vm.isLoading = false;
                    }
                } else {
                    vm.noRecord = true;
                    vm.isLoading = false;
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            } catch (error) {
                vm.isLoading = false;
                vm.ListingData = [];
            }
        },

        leftCommonSearch(value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchCondition != '') {
                    let str = value.searchConditionJson;
                    let result = str.split('=')[1];
                    this.searchCondition = result;
                }
                else {
                    this.searchCondition = "";
                }
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Edit':
                        if (row.status_name == 'Closed') {
                            action.isVisible = true;
                            action.isDisabled = true
                        }
                        else {
                            action.isVisible = true;


                        }
                        break;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },

        pagerMethod(value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'Edit':
                    this.handleEdit(item);
                    break;
            }
        },

        handleEdit(item) {
            this.LeadId = item.lead_id
            this.diagnosticDetailId = item.diagnostic_detail_id;
            this.IsShowAddDiagnosticForm = true;

        },
        async commonHeaderButtonClick(event) {
            var vm = this;
        },

        sortdata(s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },

        refreshFetchDiagnosticData() {
            var vm = this;
            vm.FetchData();
            vm.IsShowAddDiagnosticForm = false;

        },
    }
};
</script>