<template>
    <div>
        <template>
            <transition name="modal">
                <div class="modal d-block my-popups dialog">
                    <loader :is-visible="isLoading"></loader>

                    <div class="modal-dialog">
                        <div class="modal-content">
                            <div class="modal-header">
                                <slot name="headerForModal">
                                    <h5 class="modal-title">{{ leadConsentId == 0 ? $t("AddConsent") :
                                        $t("EditConsent") }}</h5>
                                </slot>
                                <button type="button" title v-on:click="closeConsent" class="close"
                                    data-original-title="Close">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>
                            </div>
                            <div class="modal-body">

                                <dynamic-form ref="dynamicform" lang="en" :buttons="buttons" :schema="FormSchema"
                                    v-on:OnSubmit="OnSubmit">
                                    <template v-slot:tgslot-Consent_datetime="{ data }">


                                        <Field name="Consent datetime" :rules="{ 'required': true }"
                                            v-slot="{ errors }">
                                            <v-date-picker :popover="popover" :minute-increment="5" mode="dateTime"
                                                class="input-group" v-model="data.fieldInfo.value">
                                                <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                    <input :class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                        :value="inputValue" v-on="inputEvents" />
                                                    <div @click="togglePopover()" class="input-group-append">
                                                        <span class="input-group-text"><em
                                                                class="fa fa-calendar"></em></span>
                                                    </div>
                                                </template>
                                            </v-date-picker>
                                            <span name="Consent datetime" class="invalid-feedback d-block">{{
                                                errors[0]
                                            }}</span>
                                        </Field>


                                    </template>
                                </dynamic-form>



                            </div>
                        </div>
                    </div>
                </div>
            </transition>
        </template>
    </div>
</template>

<script>

import DataService from "../../../services/DataService";

export default {
    props: {
        //
        LeadId: {
            type: Number,
            required: false
        },
        leadConsentId: {
            type: Number,
            required: true
        },
        EditConsentDetails: {
            type: Object,
            required: false,

        }
    },

    components: {
    },
    data() {
        return {
            attachMentFilePath: '',
            popover: {
                visibility: 'click'
            },
            disAllowedfiletypes: [],
            fileData: [],
            FormSchema: [{
                layoutType: "triple",
                Data: [
                    {
                        astype: "SlotField",
                        label: 'Consent datetime',
                        name: "Consent_datetime",
                        value: (new Date()),
                        placeholder: "",
                        config: {
                            format: "MM/DD/YYYY",
                            // onChange: this.setDateForm,
                            minDate: ''
                        },
                        validationRules: { "required": true },
                        disabled: false,
                    },
                    {
                        astype: "SelectField",
                        label: 'Consent on',
                        name: "Consent_on",
                        value: "",
                        config: {
                            options: [
                                { name: "Call / Verbal", value: "call" },
                                { name: "Form / Written", value: "form" }
                            ],

                        },
                        placeholder: this.$t('Plans'),
                        validationRules: { "required": true, max: 100 },
                    },

                    {
                        astype: "TextField",
                        label: 'Consent by',
                        name: "Consent_by",
                        value: "",
                        visibility: true,
                        validationRules: [{ "required": true }],
                        disabled: false,
                    },



                ]
            },
            {
                layoutType: "single",
                Data: [{
                    astype: "FileField",
                    showLabel: false,
                    label: this.$t('AttachItemImage'),
                    name: "AttachItemImage",
                    value: "",
                    placeholder: "",
                    FieldIndex: 0,
                    validationRules: { "required": true },
                    config: {
                        maxSize: 5,
                        accept: [
                            {
                                fileType: 'doc',
                                iconClass: 'fa-file-word-o'
                            },
                            {
                                fileType: 'docx',
                                iconClass: 'fa-file-word-o'
                            },
                            {
                                fileType: 'pdf',
                                iconClass: 'fa-file-pdf-o'
                            },
                            // {
                            //     fileType: 'txt',
                            //     iconClass: 'fa-file-text-o'
                            // },
                            // {
                            //     fileType: 'png',
                            //     iconClass: 'fa-file-image-o'
                            // },
                            {
                                fileType: 'jpg',
                                iconClass: 'fa-file-image-o'
                            },
                            {
                                fileType: 'jpeg',
                                iconClass: 'fa-file-image-o'
                            },
                            // {
                            //     fileType: 'xls',
                            //     iconClass: 'fa-file-excel-o'
                            // },
                            // {
                            //     fileType: 'xlsx',
                            //     iconClass: 'fa-file-excel-o'
                            // },
                            // {
                            //     fileType: 'csv',
                            //     iconClass: 'fa-file-excel-o'
                            // },
                        ],
                        // reject: this.disAllowedfiletypes,
                        onClickSelectedFiles: this.DownloadSingleFile,
                        onDeleteSelectedFiles: this.onDeleteSelectedFiles,
                        onChange: this.GetBase64String,
                        showSelectedFiles: [
                            // {
                            //     attachmentId: "1",
                            //     attachmentName: "",
                            //     attachmentPath: "",
                            // },
                        ],
                        showAddIcon: false,
                        onAddButtonClick: this.AddFileMore,
                        multiple: false
                    },
                }]
            }

            ],
            isLoading: false,
            buttons: [{
                type: "submit",
                class: "btn btn-success AddLeadDetail_a",
                text: `<i class='fa fa-save pr-2'></i>${this.leadConsentId === 0 ? 'Save' : 'Update'}`,
                // onclick: this.saveForm
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Cancel",
                onClick: this.closeConsent,
                isVisible: true,
            },

            ],

        };
    },

    created() {
        var vm = this;
        // vm.GetAllowFileType();
        // await vm.GetFileSettings('CRMDisallowedFileTypes');
        if (vm.leadConsentId > 0) {
            vm.editConsentDetails();
        }

    },
    methods: {
        GetFileSettings(configkey) {
            var vm = this;
            DataService.GetConfigurationSettings("configkey=" + configkey).then(
                function (response) {
                    if (response.data != "") {
                        if (configkey == 'CRMPerFileSize') {
                            vm.maxsize = response.data;
                        }
                        else {
                            // let DisallowedFileType = ".exe,.com,.js,.php,.asp,.aspx,.txt,.jpg,.png";
                            let result = vm.AttachmentDisallowedFileType(response.data);
                            vm.disAllowedfiletypes = result;
                        }
                    } else {
                        return '';
                    }

                }
            );
        },
        AttachmentDisallowedFileType(DisallowedFileType) {
            let array = [];
            let acceptFileTypeList = [];

            if (DisallowedFileType && DisallowedFileType.trim() !== '') {
                array = DisallowedFileType.split(',');

                array.forEach(function (row) {
                    let acceptFileType = {};
                    acceptFileType.fileType = row.replace('.', '');

                    if (acceptFileType.fileType === "doc" || acceptFileType.fileType === "docx") {
                        acceptFileType.iconClass = "fa-file-word-o";
                    } else if (acceptFileType.fileType === "xls" || acceptFileType.fileType === "xlsx") {
                        acceptFileType.iconClass = "fa-file-word-o";
                    } else if (acceptFileType.fileType === "txt") {
                        acceptFileType.iconClass = "fa-file-text-o";
                    } else if (acceptFileType.fileType === "jpg" || acceptFileType.fileType === "bmp" || acceptFileType.fileType === "gif" || acceptFileType.fileType === "jpeg" || acceptFileType.fileType === "png") {
                        acceptFileType.iconClass = "fa-file-image-o";
                    } else if (acceptFileType.fileType === "mp4" || acceptFileType.fileType === "mov") {
                        acceptFileType.iconClass = "fa-file-video-o";
                    } else if (acceptFileType.fileType === "mp3") {
                        acceptFileType.iconClass = "fa-file-audio-o";
                    } else if (acceptFileType.fileType === "pdf") {
                        acceptFileType.iconClass = "fa-file-audio-o";
                    } else {
                        acceptFileType.iconClass = "fa-file-o";
                    }

                    acceptFileTypeList.push(acceptFileType);
                });
            }

            return acceptFileTypeList;
        },


        editConsentDetails() {

            var vm = this;
            vm.FormSchema[0].Data[0].value = vm.EditConsentDetails.Consent_datetime;
            vm.FormSchema[0].Data[1].value = vm.EditConsentDetails.Consent_on;
            vm.FormSchema[0].Data[2].value = vm.EditConsentDetails.Consent_by;
            if (vm.EditConsentDetails.file_path) {
                vm.attachMentFilePath = vm.EditConsentDetails.file_path;
                const fileName = vm.EditConsentDetails.file_path.substring(vm.EditConsentDetails.file_path.lastIndexOf('/') + 1);
                let obj = {
                    attachmentId: "1",
                    attachmentName: fileName,
                    attachmentPath: vm.EditConsentDetails.file_path,
                    attachmentDesc: 'Attachment details'
                }
                vm.FormSchema[1].Data[0].config.showSelectedFiles.push(obj)
            }

        },
        closeConsent() {
            this.$parent.IsShowConsentDetailsForm = false
        },
        onDeleteSelectedFiles() {
            var vm = this;
            if (vm.EditConsentDetails) {
                // vm.EditConsentDetails.file_path = '';
                vm.attachMentFilePath = ''
            }
            // vm.$delete(this.FormSchema[1].Data[0].config, 'showSelectedFiles');
            vm.FormSchema[1].Data[0].config.showSelectedFiles = [];
        },

        getFileExtension(type) {
            const mimeType = type;
            const extension = mimeType.split('/')[1];
            return extension;
        },

        async DownloadSingleFile(fileUrl) {
            var vm = this;
            vm.isLoading = true;
            if (fileUrl.attachmentPath == null || fileUrl.attachmentPath == "") {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("NoFileUrl"), "warning", true, vm.$t("Alert"));
            }
            else {
                var params = `FileUrl=${fileUrl.attachmentPath}`
                await DataService.DownloadSingleFile(params).then((response) => {
                    if (response.data != null) {
                        var fileURL = window.URL.createObjectURL(new Blob([response.data]));
                        const fileName = fileUrl.attachmentPath.substring(fileUrl.attachmentPath.lastIndexOf('/') + 1);
                        var fileLink = document.createElement('a');
                        fileLink.href = fileURL;
                        fileLink.setAttribute('download', fileName);
                        document.body.appendChild(fileLink);
                        fileLink.click();
                        vm.isLoading = false;
                    }
                    else {
                        vm.isLoading = false;
                        vm.ShowAlert(vm.$t("FileNotDownload"), "warning", true, vm.$t("Alert"));
                    }
                })
            }
        },



        GetBase64String(evt) {
            try {
                var vm = this;
                vm.fileData = [];
                var f = evt.target.files[0]; // FileList object
                var reader = new FileReader();
                reader.onload = (function (theFile) {
                    return function (e) {
                        var binaryData = e.target.result;
                        var base64StringEncoded = window.btoa(binaryData);
                        var fileName = f.name;
                        vm.fileName = fileName;
                        var n = fileName.lastIndexOf(".");
                        var extensionName = fileName.substring(n + 1, fileName.length);
                        vm.fileExt += "." + extensionName;
                        var attachemnetMime = '{"ContentType":"' + f.type + '","Size":"' + f.size + '","Extension":"' + extensionName + '"}';
                        var fileSize = f.size;
                        vm.fileSize = fileSize;
                        var fileObj = {
                            attachement_mime: attachemnetMime,
                            fileName: fileName,
                            base64String: base64StringEncoded,
                            fileSize: f.size,
                            contentType: f.type
                        };
                        vm.fileData.push(fileObj);
                    };
                })(f);
                reader.readAsBinaryString(f);
            }
            catch (ex) {
                //
            }
        },

        async OnSubmit(formFields) {
            let vm = this;
            vm.isLoading = true;
            const obj = {
                leadId: vm.LeadId,
                leadConsentId: vm.EditConsentDetails?.lead_consent_id || 0,
                consentDateTime: vm.$options.filters.formatDateTime(formFields.Consent_datetime),  
                consentOn: formFields.Consent_on,
                ConsentBy: formFields.Consent_by,
                attachment: JSON.stringify(vm.fileData),
                PreviousURL: vm.attachMentFilePath || ''
            };
            let formData = new FormData();
            formData.append("postString", JSON.stringify(obj));
            try {
                const response = await DataService.SaveConsentDetails(formData);
                if (response.status == 200) {
                    vm.isLoading = false;
                    if (response.data.Result == '1') {
                        vm.ShowAlert(vm.$t('SaveConsentDetails'), "success");
                        vm.$emit("FetchDataConsent");
                    }
                    else if (response.data.Result == '2') {
                        vm.ShowAlert(vm.$t('UpdateConsentDetails'), "success");
                        vm.$emit("FetchDataConsent");
                    }
                    else {
                        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                    }
                }
            } catch (error) {
                vm.isLoading = false;
            }
        },



    },
};
</script>
