<template>
    <transition name="modal">
      <div class="my-popups">
        <div class="modal d-block">
          <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
              <div class="modal-header">
                <h5 class="modal-title">{{ $t('Notes') }}</h5>
                <button v-on:click="$emit('close')" href="javascript:;" class="close">
                    <em class="fa fa-times" aria-hidden="true"></em>
                </button>
              </div>
              <div class="modal-body" style="max-height:600px;overflow-y:auto;">
                <div v-bind:class="{ 'feedback-ticket feedback-ticket-present-answersDiv mb-2': true}" >
                    <div class="heading-border">
                        <h5 class="h5 mb-2"> <span> {{ $t("AddNotes") }}</span></h5>
                    </div>
                    <div class="feedback-ticket-content">
                        <Form v-slot="{ values, meta }" ref="form">
                            <div class="feedback-conversation-box" style="padding:none;">
                                <div class="row">
                                    <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left">
                                        <div class="form-group">
                                            <label>{{ $t("Visibility") }} :</label>
                                            <div class="pl-0 border-0">
                                                <div class="form-check form-check-inline">
                                                    <div class="custom-control custom-radio custom-control-inline">
                                                        <input type="radio" v-model="IsPrivate" id="radio_Public" class="custom-control-input dynamic" value="0" name="rdo_ForNote" checked="checked" />
                                                            <label class="custom-control-label" for="radio_Public"> {{ $t("Public") }} 
                                                        </label>
                                                    </div>
                                                </div>
                                                <div class="form-check form-check-inline">
                                                    <div class="custom-control custom-radio custom-control-inline">
                                                        <input v-model="IsPrivate" id="radio_Private" type="radio" class="custom-control-input" value="1" name="rdo_ForNote" />
                                                            <label class="custom-control-label" for="radio_Private"> {{ $t("Private") }}
                                                        </label>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div class="conversation-content feedback-conversation-content">                       
                                    <Field name="note" :rules="{ 'required': true }" label="Note" v-slot="{ errors }">
                                        <ckeditor :editor="editor" v-model="note" ></ckeditor>
                                        <span name="note" class="invalid-feedback d-block">{{ errors[0] }}</span>
                                    </Field>
                                </div>
                            </div>
                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 p-0 mt-3 text-right">
                                <div class="form-group mb-0">
                                    <div class="search-btm-btn">
                                        <a href="javascript:;" class="btn btn-success save-btn mr-1" @click.once="saveNote(values, meta)" title="Save">
                                            <em class="fa fa-save pr-2 text-white"></em>{{ $t("Save") }} 
                                        </a>
                                        <a href="javascript:;" class="btn btn-danger delete-btn" v-on:click="$emit('close')" title="Cancel">
                                            <em class="fa fa-close pr-2 text-white"></em>{{ $t("Cancel") }}
                                        </a>
                                    </div>
                                </div>
                            </div>
                        </Form>
                    </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </transition>
</template>
<script>
import LeadDataService from "../../../services/DataService";
export default{
    props: {
        sourceId: {
            type: String,
            default: ''
        },
        submodulecode: {
            type: String,
            default: ''
        }
    },
    data(){
        return{
            modulename:"CRM",
            IsPrivate: "0",
            note: '',
            editor: this.CLASSIC_EDITOR,
            crmNoteId: null,
        }
    },
    created(){
    },
    methods: {
        saveNote: function (values, meta) {
            var vm = this;    
            vm.$refs.form.validate().then((result) => {
                if (result) {
                    var data = {
                        sourceId: vm.sourceId,
                        moduleName: vm.modulename,
                        subModuleCode: vm.submodulecode,
                        note: vm.note,
                        isPrivate: vm.IsPrivate,
                        crmNotesId: vm.crmNoteId
                    };
                    var objectPostString = JSON.stringify(data);
                    LeadDataService.SaveNoteData(objectPostString).then(function (response) {
                        if (response.data[0].Status == "Success") {
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Note')]), "Success", true, vm.$t("Alert"));
                            vm.$emit('close');
                        }
                        else{
                            vm.ShowAlert(vm.$t('AddedError', [vm.$t('Note')]), "Failure", true, vm.$t("Alert"));
                        }

                    })
                }
            })
        },
    }
}
</script>