                                            <div class="row">
                                                <div class="col-md-12 col-lg-12">
                                                    <div class="row card-view no-bg custom-box-width customboxnewwidth" style="max-height: 520px; overflow-y: auto;">
                                                        <div :class="{'col-md-12 col-lg-12 col-xl-12 mb-3':true, 'task':item.activity_type && item.activity_type.toLowerCase()=='task', 
                                                        'call':item.activity_type && item.activity_type.toLowerCase()=='call',
                                                        'followup':item.activity_type && item.activity_type.toLowerCase()=='followup'}" v-for="(item, index) in FollowUpData" :key="index">
                                                          
                                                            <div class="card-box blue-bg-light pb-0">
                                                                <div class="card-heading">
