                                                                            <div class="float-left"><em aria-hidden="true" class="fa fa-calendar-o ml-4"></em>{{item.followup_notification_schedule | formatDateTime}}</div>
                                                                        </div>
                                                                    </span>
                                                                    <div class="card-action d-none"><a title="Edit Notes" alt="Edit Notes" href="javascript:;" class="round-icon-small btn-success-light"><em class="fa fa-edit"></em></a></div>
