                                                                            <p>{{ item.followup_notification_message }}</p>
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                                
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div v-if="FollowUpData && FollowUpData.length==0" class="text-center text-danger no-record p-2 border">
                                                        {{$t('NoRecordfound')}}
                                                </div>
                                        </div>
                                    </div>
