                    </div>

                </div>

            </div>
            <div class="col-md-4 p-0 mb-2">
                <div class="listing tab-content">
                    <div id="divconversationbox" class="col-12 d-flex border border-bottom-0 bg-f5f5f5">
                        <div class="col-md-6 pl-0">
                            <h6 class="py-3 mb-0">{{ $t('Activities') }}</h6>
                        </div>
                        <div class="col-md-6 text-right pr-0 bottom_filter_button">
                            <a href="javascript:;" id="ancActivityExpandAllCollapseAll" @click="expandAllCollapseAll" :title="$t('ExpandAllCollapseAll')" class="position-relative" style="z-index: 999;">
