                    <div id="tab-ticket-content" role="tabpanel" aria-labelledby="Activities-tab"
                        class="tab-pane fade show activity-tab active pt-3 maxheight800">
                        <div class="d-md-inline-block w-100">
                            <div class="listing">
                                <div id="accordion" class="w-100">
                                    <div class="card" v-for="(item, parentIndex) in timelinedata" :key="parentIndex">
                                        <div class="card-header">
