                    <span>{{ $t('DiagnosticDetails') }}</span>
                </h5>
            </div>
            <DiagnosticDetails :key="leadId"  :sourceid="leadId" ></DiagnosticDetails>
        </div>
        <div class="clearfix"></div>
        <div class="col-md-12 p-0 mt-3">
            <div class="row flex-row-reverse mt-2">
                <div class="col-lg-12 text-right">
                    <div class="search-btm-btn">
                        <a href="javascript:;" @click="goToPrevious" :title="$t('Back')" :class="{'btn btn-secondary mr-1':true,'disabled':previousLeadId === leadId}">
                            <em class="fa fa-angle-double-left  mr-1"></em>
                             <span>{{ $t('Back') }}</span>
                        </a>
                        <a href="javascript:;" @click="goToNext" :title="$t('Next')" :class="{'btn btn-primary formbtn widthhalf':true,'disabled':nextLeadId === leadId}">
                            {{ $t('Next') }}
                            <em class="fa fa-angle-double-right pr-2"></em>
                        </a>
                    </div>
                </div>

            </div>
        </div>
        <modaladdnote v-if="isShowNotePopup" @close="isShowNotePopup = false, FetchData(), FetchNotes()" :sourceId="leadId" submodulecode="CRM_LEADS"></modaladdnote>
        <modalevent v-if="showAddEventModal" @close="showAddEventModal = false, FetchFollowUps(), FetchData()" modulename="CRM" submodulecode="CRM_LEADS" :sourceid="leadId">
            <h5 slot="header" class="modal-title">{{ $t('FollowUp') }}</h5>
        </modalevent>
        <modalcall
            v-if="showCallModal"
            :modalCallItem="null" :sourceId="leadId" :subModuleCode="'CRM_LEADS'"
            @close="showCallModal = false, FetchData()">
            <h5 slot="header" class="modal-title">{{ $t('Schedule') }} {{ $t('Call') }}</h5>
        </modalcall>
    </section>
</template>

<script>
import LeadDataService from "../../../services/DataService";
import modaladdnote from "../../../components/Common/Modal/modaladdnote.vue";
import modalevent from "../../../components/Common/Modal/modalevent.vue";
import VueBootstrapTypeahead from 'vue-bootstrap-typeahead';
import DiagnosticDetails from  "../../../components/Common/Modal/DiagnosticDetails.vue"
import modalcall from "../../../components/Common/Modal/modalcall.vue";

export default {
    components: {
        VueBootstrapTypeahead,
        modaladdnote,    
        modalevent,
        DiagnosticDetails,
        modalcall
    },
    data() {
        return {
            isLoading: true,
            LeftViewData: [],
            timelinedata: [],
            additionalOwnerPermission: [],
            FollowUpData: [],
            noteData: [],
            StatusListForListing: [],
            isShowNotePopup: false,
            showAddEventModal: false,
            isExpanded: false,
            LeadStatus: "",
            clienFirstName: "",
            clientLastName: "",
            leadName: "--",
            leadId: 0,
            previousLeadId: 0,
            nextLeadId: 0,
            //currentIndex: 0,
            LeadListData: [],
            searchText: "",
            selectedId: null,
            showCallModal: false,
        }
    },
    // computed: {
    //     currentValue() {
    //         return this.LeadListData[this.currentIndex];
    //     },
    //     previousValue() {
    //         return this.currentIndex > 0 ? this.LeadListData[this.currentIndex - 1] : null;
    //     },
    //     nextValue() {
    //         return this.currentIndex < this.LeadListData.length - 1 ? this.LeadListData[this.currentIndex + 1] : null;
    //     }
    // },
    
    async created() {
        var vm = this;

        if(vm.$route.query.id && vm.$route.query.id > 0){
            vm.leadId = vm.$route.query.id;
        }

        //await vm.GetLeadIds();
        await vm.getStatuslistForListing("CRM", "en");
        await vm.FetchData();
        await vm.FetchFollowUps();
        await vm.FetchNotes();
        
    },
    methods: {
        onSearchInput() {
            var vm = this;
            if (vm.searchText.length >= 3) {
                vm.GetLeadIds(vm.searchText);
            }
        },
        GetLeadIds: async function () {
            var vm = this;
            var param = `search=${vm.searchText}`;
            await LeadDataService.GetLeadIds(param).then(function (response) {
                if (response.data != null && response.data.data.length > 0) {
                    vm.LeadListData = response.data.data;
                    // if(vm.$route.query.id && vm.$route.query.id > 0){
                    //     vm.leadId = vm.$route.query.id;
                    //     vm.currentIndex = vm.LeadListData.findIndex(x=>x.lead_id==vm.leadId);
                    // }else{
                    //     vm.leadId = vm.LeadListData[0].lead_id;
                    // }
                }
            });
        },
        FetchData: async function () {
        var vm = this;
        vm.isLoading=true;
        vm.timelinedata = [];
        vm.LeftViewData = [];
       var ApiURL= `id=${vm.leadId}&moduleName=CRM&subModuleCode=CRM_LEADS&reqFrom=VIEW_LEAD_DETAILS`
       await LeadDataService.FormLayoutView(ApiURL).then(function (response) {
            var fullLeftJSON = response.data.LEFTDATA;
            vm.leadId = response.data.RECORD_ID;
            vm.previousLeadId = response.data.PREVIOUS_RECORD_ID;
            vm.nextLeadId = response.data.NEXT_RECORD_ID;
            vm.isLoading=false;
            fullLeftJSON = $.grep(fullLeftJSON, function (element, index) {
                if (element.name == "status_id") {
                    vm.LeadStatus = vm.FilterDDLandNormalValue(element.value);
                }
                else if (element.name == "client_first_name") {
                    vm.clienFirstName = element.value != null ? element.value : "";
                } else if (element.name == "client_last_name") {
                    vm.clientLastName = element.value != null ? element.value : "";
                }
                return element.form_field_visibility == "YES";
            });

            if (response.data.RIGHTDATA != null && response.data.RIGHTDATA.length > 0) {
                var fullJSON = response.data.RIGHTDATA;
                var gruopBy = "";
                $.each( fullJSON, $.proxy(function (index, item) { 
                    gruopBy = vm.$options.filters.formatDate(item.Complete_datetime);
                    var chkGroup = $.grep(vm.timelinedata, function (element, index) {
                        return element.groupKey == gruopBy;
                    });
                    if (chkGroup.length == 0) {
                        var returnedData = $.grep(fullJSON, function (element, index) {
                        return vm.$options.filters.formatDate(element.Complete_datetime) == gruopBy;
                        });
                        if (returnedData.length > 0) {
                        var objGroup = {
                            groupKey: gruopBy,
                            groupData: returnedData,
                        };
                        vm.timelinedata.push(objGroup);
                        }
                    }
                    }, this)
                );
                vm.isLoading=false;
                } 

            if (fullLeftJSON != null && fullLeftJSON.length > 0) {
            var groupId = fullLeftJSON[0].group_id;
            $.each( fullLeftJSON, $.proxy(function (index, item) {
                var chkGroup = $.grep(vm.LeftViewData, function (element, index) {
                    return element.group_id == groupId;
                });
                if (chkGroup.length == 0) {
                    var returnedData = $.grep(
                    fullLeftJSON,
                    function (element, index) {
                        return element.group_id == groupId;
                    });
                    vm.leadName = vm.clienFirstName + " " + vm.clientLastName;
                    returnedData = returnedData.sort(function (a, b) {
                    var a1 = a.display_order,
                        b1 = b.display_order;
                    if (a1 == b1) return 0;
                    return a1 > b1 ? 1 : -1;
                    });
                    if (returnedData.length > 0) {
                    var objGroup = {
                        group_id: groupId,
                        group_name: returnedData[0].group_name,
                        group_display_name: returnedData[0].group_display_name,
                        LeftViewData: returnedData,
                    };
                    vm.LeftViewData.push(objGroup);
                    }
                }
                groupId = item.group_id;
                }, this)
            );
            }
                vm.additionalOwnerPermission = response.data.PERMISSION_DATA;
            });
        },
        async FetchFollowUps(){
                var vm = this;
                vm.FollowUpData = [];
                var ApiURL= `id=${vm.leadId}&moduleName=CRM&subModuleCode=CRM_LEADS`
                await LeadDataService.ActivityListing(ApiURL).then(function (response) {                      
                if (response.data != "" && response.data != null && response.data.data.length > 0) {
                    vm.FollowUpData = response.data.data;
                }

            });
        },
        getStatuslistForListing: async function (StatusType, lang) {
            var vm = this;
            var url = "langCode=" + lang + "&statusType=" + StatusType + "&hasglobal=true";
            await LeadDataService.statusdropdown(url).then(function (response) {
                if (response.data.status == "Success") {
                    var json = response.data.result;
                    vm.StatusListForListing = json.data;
                }
            });
        },
        async FetchNotes(){
            var vm = this;
            vm.noteData = [];
            var ApiURL= `id=${vm.leadId}&moduleName=CRM&subModuleCode=CRM_LEADS`
            vm.noteData = [];
            await LeadDataService.NoteListing(ApiURL).then(function (response) {
                if (response.data != null && response.data.data.length > 0) {
                    vm.noteData = response.data.data;
                }
            });
        },
        FilterDDLandNormalValue: function (item) {
            if (item && item.length > 0) {
                try {
                    return JSON.parse(item)[0].name;
                } catch (ex) {
                    return "";
                }
            } else {
                return "";
            }
        },
        openShowNotePopup: function () {
            var vm = this;
            if ( typeof vm.checkForAdditionalPermission !== "undefined" && !vm.checkForAdditionalPermission("AddNote")) {
                vm.ShowAlert( vm.$t("additionalOwnerAuthorityWarning"), "warning", true, vm.$t("Alert") );
            } else {
                vm.isShowNotePopup = true;
            }
        },
        openCallEvent: function () {
            if ( typeof this.checkForAdditionalPermission !== "undefined" && !this.checkForAdditionalPermission("AddAcitvities") ) {
                this.ShowAlert(this.$t("additionalOwnerAuthorityWarning"), "warning", true, this.$t("Alert") );
            } else {
                this.showCallModal = this.showCallModal ? false : true;
            }
        },
        checkForAdditionalPermission: function (TypeCode) {
            var rtrn = true;
            if ( this.additionalOwnerPermission != null && this.additionalOwnerPermission.length > 0) {
                var prmsn = this.additionalOwnerPermission.filter(function (c) {
                    return c.permission_code == TypeCode;
                });
                if (prmsn.length == 0) {
                    rtrn = false;
                }
            }
            return rtrn;
        },
        openAddNewEvent: function () {
            var vm = this;
            if ( typeof vm.checkForAdditionalPermission !== "undefined" && !vm.checkForAdditionalPermission("AddAcitvities")) {
                vm.ShowAlert( vm.$t("additionalOwnerAuthorityWarning"),"warning", true, vm.$t("Alert") );
            } else {
                vm.showAddEventModal = vm.showAddEventModal ? false : true;
            }
        },
        expandAllCollapseAll() {
            this.isExpanded = !this.isExpanded;
        },
       async goToPrevious() {
            var vm = this;
            vm.searchText = "";
            vm.selectedId = null;
            const typeaheadInput = vm.$refs.typeahead.$el.querySelector('input');
            if (typeaheadInput) {
                typeaheadInput.value = '';
                typeaheadInput.dispatchEvent(new Event('input'));
            }
            // if (vm.currentIndex > 0) {
            //     vm.currentIndex--;
            // }
            //vm.leadId = vm.LeadListData[vm.currentIndex].lead_id;
            vm.leadId = vm.previousLeadId;
            await vm.FetchData();
            await vm.FetchFollowUps();
            await vm.FetchNotes();
        },
       async goToNext() {
            var vm = this;
            vm.searchText = "";
            vm.selectedId = null;
            const typeaheadInput = vm.$refs.typeahead.$el.querySelector('input');
            if (typeaheadInput) {
                typeaheadInput.value = '';
                typeaheadInput.dispatchEvent(new Event('input'));
            }
            // if (vm.currentIndex < vm.LeadListData.length - 1) {
            //     vm.currentIndex++;
            // }
            //vm.leadId = vm.LeadListData[vm.currentIndex].lead_id;
            vm.leadId = vm.nextLeadId;
            await vm.FetchData();
            await vm.FetchFollowUps();
            await vm.FetchNotes();
        },
        onSelect(lead_name) {
            var vm = this;
            const selectedLead = vm.LeadListData.find(item => item.lead_name === lead_name);
            if (selectedLead) {
                vm.selectedId = selectedLead.lead_id;
                //vm.currentIndex = vm.LeadListData.findIndex(x=>x.lead_id==vm.selectedId);
            }
        },
        async Search(){
            var vm = this;
            if (vm.selectedId) {
                vm.leadId = vm.selectedId;
                await vm.FetchData();
                await vm.FetchFollowUps();
                await vm.FetchNotes();
            } else {
                console.log('No valid lead selected');
            }

        },
        async Clear(){
            var vm = this;
            vm.searchText = "";
            vm.selectedId = null;
            const typeaheadInput = vm.$refs.typeahead.$el.querySelector('input');
            if (typeaheadInput) {
                typeaheadInput.value = '';
                typeaheadInput.dispatchEvent(new Event('input'));
            }
            vm.leadId = 0;
            await vm.FetchData();
            await vm.FetchFollowUps();
            await vm.FetchNotes();
        }
        
    },
}
</script>

